import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class CommandInjectionExample {
    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
        System.out.print("Enter a website to ping: ");
        String website = reader.readLine();

        // Vulnerable code - user input is directly concatenated into the command
        String command = "ping " + website;

        Process process = Runtime.getRuntime().exec(command);
        BufferedReader outputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));

        String output;
        while ((output = outputReader.readLine()) != null) {
            System.out.println(output);
        }
    }
}

